// In worker.go eventHandler(), inside grouphandler.NewNoPublishingHandler:
grouphandler.NewGroupEventHandler(func(ctx context.Context, event *somepkg.SomeEvent) error {
	return w.opts.EventBus.Publish(ctx, events.RecalculateEvent{
		Entitlement:         pkgmodels.NamespacedID{Namespace: event.Namespace.ID, ID: event.EntitlementID},
		OriginalEventSource: metadata.ComposeResourcePath(event.Namespace.ID, metadata.EntityEntitlement, event.EntitlementID),
		AsOf:                event.OccurredAt,
		SourceOperation:     events.OperationTypeEntitlementCreated, // pick closest matching
	})
}),

type (
	GetMyHandlerRequest  = struct{ Namespace, SubjectKey, EntitlementID string }
	GetMyHandlerResponse = *api.Entitlement
	GetMyHandlerParams   = struct{ SubjectKey, EntitlementID string }
)
type GetMyHandler httptransport.HandlerWithArgs[GetMyHandlerRequest, GetMyHandlerResponse, GetMyHandlerParams]

func (h *entitlementHandler) GetMy() GetMyHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, p GetMyHandlerParams) (GetMyHandlerRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return GetMyHandlerRequest{}, err }
			return GetMyHandlerRequest{Namespace: ns, SubjectKey: p.SubjectKey, EntitlementID: p.EntitlementID}, nil
		},
		func(ctx context.Context, req GetMyHandlerRequest) (GetMyHandlerResponse, error) {
			cust, err := h.resolveCustomerFromSubject(ctx, req.Namespace, req.SubjectKey)
			if err != nil { return nil, err }
			res, err := h.connector.GetEntitlement(ctx, req.Namespace, cust.ID, req.EntitlementID)
			if err != nil { return nil, err }
			return Parser.ToAPIGeneric(&entitlement.EntitlementWithCustomer{Entitlement: *res, Customer: *cust})
		},
		commonhttp.JSONResponseEncoder[GetMyHandlerResponse],
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("getMy"), httptransport.WithErrorEncoder(GetErrorEncoder()))...,
	)
}
